var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"……그래서, 변명은 그게 끝인가? 용병 혐오자 양반.","JPN":"……で、言い訳はそれで終わりか？　傭兵嫌いさん。","ENG":"... So, that’s your excuse, mercenary hater?","TWN":"……你還要再繼續辯解嗎？討厭傭兵的傢伙。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"……대체 몇 번을 말해?! 그건 오해라니까!","JPN":"……いったい何回言えばわかるんだ！？　それは誤解だって！","ENG":"How many times do I have to tell you? It was all a misunderstanding!","TWN":"……到底要我說幾次？！那是誤會！"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"오해?","JPN":"誤解？","ENG":"Misunderstanding?","TWN":"誤會？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"자네가 불쌍한 용병들을 다 때려죽이고 날 초공간으로 날려버리려고 했던 게 모두 오해일 뿐이라.","JPN":"あんたが可哀想な傭兵たちを全員殴り殺して、\\n俺を超空間にぶっ飛ばそうとしたのがすべて誤解だって？","ENG":"You tried to kill all those mercenaries, and then send me to hyperspace. And you claim that it was all just a misunderstanding?","TWN":"你把那些可憐的傭兵全都打死後，還想把我弄到超空間，這些全都是誤會？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"참 편리하군. 그렇지 않나?","JPN":"よく言うぜ、なあ？","ENG":"How convenient. Don’t you think?","TWN":"誤會這兩個字還真好用，你說是不？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"때려죽인 적 없어! 그리고 초공간으로 날아간 건 나였잖아!","JPN":"殴り殺してなんかない！　そもそも、超空間に飛ばされたのは俺の方だろ？","ENG":"I didn’t kill them! And I was the one who was sent into hyperspace!","TWN":"我沒有打死人！而且跑到超空間去的明明就是我！"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"흐음……. 그랬던 것 같기도 하고, 아닌 것 같기도 하고…….","JPN":"ふむ……そうだったような、そうじゃなかったような……","ENG":"Hmm... Maybe you were. Or maybe you weren’t.","TWN":"嗯……你好像有說過，又好像沒有……"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"……다시 말하지만 그건 리플레이서의 협력자들을 색출하고 로스트 쉽을 확보하기 위한 작전이었어.","JPN":"……もう一度言うが、あれはリプレイサーの協力者をあぶり出して、\\nロストシップを確保するための作戦だったんだ。","ENG":"... I’m telling you, I did what I did to find the Replacer spies and secure the Lost Ship.","TWN":"……我再說一次，那是為了找出克隆集團的同夥和失落艦船的策略！"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"항복 권유를 거부하고 교전 상황으로 만든 건 오히려 그쪽이었지!","JPN":"降伏勧告を断って交戦状態にしたのはむしろそっちだろうが！","ENG":"You were the one who refused to surrender and started fighting!","TWN":"況且，拒絕投降導致雙方開戰的罪魁禍首，明明就是閣下！"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"얌전히 항복한 다른 녀석들은 제네바 협약에 따라 전시 포로로 대우해 줬다고.","JPN":"大人しく投降した他の奴らは、\\nジュネーブ条約に基づいて戦時捕虜として待遇してやったんだぞ。","ENG":"Those who surrendered were treated fairly in accordance with the Geneva Conventions.","TWN":"人家明明就說，只要乖乖投降，就根據日內瓦公約給予戰俘的待遇！"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"미안하지만 어딘지도 모르는 이면세계에서 남에게 내 목숨을 맡기는 취미는 없거든.","JPN":"悪いが、未知の裏世界で他人に自分の命を預ける趣味はないんだ。","ENG":"Sorry, but I don’t like letting others decide my fate in the Counterside.","TWN":"很抱歉，我沒興趣在陌生的異界裡把性命交給其他人。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"그리고 로스트 쉽에서도 미래에서 온 살인 기계처럼 날 제거하려고 하지 않았나?","JPN":"それにロストシップに乗ってからも、未来から来た殺人兵器みたいに俺を消そうとしただろ？","ENG":"Plus, you tried to kill me in the Lost Ship as well, like a killing machine sent from the future.","TWN":"而且在失落艦船裡，還有像是來自未來的殺人機器想殺我欸？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"물론 실패했지만 말이야.","JPN":"もちろん失敗したがな。","ENG":"You failed, though.","TWN":"雖然是沒有成功。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"죽인다고 한 적 없다니까! 다리만 부러뜨린다고 했었지!","JPN":"殺すなんて言ってなかっただろ！　足を折ってやるみたいなことは言ったけど！","ENG":"I didn’t try to kill you! I only wanted to break your legs!","TWN":"我沒有說要殺掉你！只說要打斷你的腿而已！"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"애초에 내가 끝장을 보려고 했으면 그쪽이 아직 살아 있을 것 같아?","JPN":"そもそも俺が本気だったら、そっちこそこうやって生き延びられたと思うか？","ENG":"If I really wanted to kill you, you wouldn’t be here.","TWN":"要是我想殺你的話，閣下現在還能活著嗎？"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"하, 패배자의 변명이 아주 달콤하군.","JPN":"へっ、負け犬のくせに口だけは達者だな。","ENG":"Hah, says a loser.","TWN":"哈，失敗者總是喜歡找藉口。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"아무튼 기억해 두라고, 제이슨…… 뭐시기 대령님.","JPN":"とにかく覚えておけよ、ジェイソン……なんとか大佐殿。","ENG":"Anyway, never forget, Colonel Jason... whatever your name is.","TWN":"總之你記住，傑森……什麼上校。"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOHN_MASON_NULL_AVOID","text":{"KOREA":"그쪽에게 패배를 맛 보여 준 최고의 두뇌파 용병.","JPN":"あんたに敗北を味わわせた最高の頭脳派傭兵、","ENG":"This is the Intelligent Mercenary who defeated you.","TWN":"讓你嚐到失敗滋味的這個人，"},"stage":{"bg":"CLUB1","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_AVOID","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};